import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';

const Medicines = () => {
  const { t } = useTranslation();
  const [medicines, setMedicines] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [stockFilter, setStockFilter] = useState('all'); // all, low_stock, out_of_stock

  // Dummy data for demonstration
  const dummyMedicines = [
    {
      id: '1',
      name: 'Paracetamol 500mg',
      generic_name: 'Acetaminophen',
      manufacturer: 'Cipla Ltd',
      price: 25.50,
      stock_quantity: 150,
      expiry_date: '2025-12-31',
      category: 'Pain Relief',
      description: 'Pain reliever and fever reducer',
      requires_prescription: false
    },
    {
      id: '2',
      name: 'Amoxicillin 250mg',
      generic_name: 'Amoxicillin',
      manufacturer: 'Sun Pharma',
      price: 85.00,
      stock_quantity: 8,
      expiry_date: '2024-08-15',
      category: 'Antibiotics',
      description: 'Antibiotic for bacterial infections',
      requires_prescription: true
    },
    {
      id: '3',
      name: 'Cetirizine 10mg',
      generic_name: 'Cetirizine HCl',
      manufacturer: 'Dr. Reddy\'s',
      price: 45.00,
      stock_quantity: 0,
      expiry_date: '2025-03-20',
      category: 'Antihistamines',
      description: 'Allergy relief medication',
      requires_prescription: false
    },
    {
      id: '4',
      name: 'Metformin 500mg',
      generic_name: 'Metformin HCl',
      manufacturer: 'Lupin',
      price: 120.00,
      stock_quantity: 75,
      expiry_date: '2025-11-10',
      category: 'Diabetes',
      description: 'Type 2 diabetes management',
      requires_prescription: true
    },
    {
      id: '5',
      name: 'Omeprazole 20mg',
      generic_name: 'Omeprazole',
      manufacturer: 'Ranbaxy',
      price: 65.00,
      stock_quantity: 5,
      expiry_date: '2024-12-05',
      category: 'Gastric',
      description: 'Proton pump inhibitor for acid reflux',
      requires_prescription: true
    },
    {
      id: '6',
      name: 'Vitamin D3 60000 IU',
      generic_name: 'Cholecalciferol',
      manufacturer: 'Abbott',
      price: 95.00,
      stock_quantity: 200,
      expiry_date: '2026-01-15',
      category: 'Vitamins',
      description: 'Vitamin D supplement',
      requires_prescription: false
    }
  ];

  useEffect(() => {
    fetchMedicines();
  }, []);

  const fetchMedicines = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      // In production, uncomment the API call below
      // const response = await medicineAPI.getAll();
      // setMedicines(response.data);
      
      // Simulate API delay
      setTimeout(() => {
        setMedicines(dummyMedicines);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching medicines:', error);
      setError('Failed to load medicines');
      setMedicines(dummyMedicines); // Fallback to dummy data
      setLoading(false);
    }
  };

  const getStockStatus = (quantity) => {
    if (quantity === 0) return 'out_of_stock';
    if (quantity < 10) return 'low_stock';
    return 'in_stock';
  };

  const getStockStatusText = (quantity) => {
    const status = getStockStatus(quantity);
    switch (status) {
      case 'out_of_stock': return t('out_of_stock');
      case 'low_stock': return t('low_stock');
      default: return t('in_stock');
    }
  };

  const getStockStatusIcon = (quantity) => {
    const status = getStockStatus(quantity);
    switch (status) {
      case 'out_of_stock': return <FaTimesCircle className="text-red-500" />;
      case 'low_stock': return <FaExclamationTriangle className="text-yellow-500" />;
      default: return <FaCheckCircle className="text-green-500" />;
    }
  };

  const filteredMedicines = medicines.filter(medicine => {
    const matchesSearch = medicine.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         medicine.generic_name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = !selectedCategory || medicine.category === selectedCategory;
    
    let matchesStock = true;
    if (stockFilter === 'low_stock') {
      matchesStock = medicine.stock_quantity > 0 && medicine.stock_quantity < 10;
    } else if (stockFilter === 'out_of_stock') {
      matchesStock = medicine.stock_quantity === 0;
    }
    
    return matchesSearch && matchesCategory && matchesStock;
  });

  const categories = [...new Set(medicines.map(medicine => medicine.category))];

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN');
  };

  const isExpiringSoon = (expiryDate) => {
    const today = new Date();
    const expiry = new Date(expiryDate);
    const timeDiff = expiry.getTime() - today.getTime();
    const daysDiff = Math.ceil(timeDiff / (1000 * 3600 * 24));
    return daysDiff <= 30;
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading medicines...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 pb-40">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          {t('medicines')} Inventory
        </h1>
        <p className="text-gray-600">
          Real-time medicine stock and availability information
        </p>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-lg shadow-sm border p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {/* Search */}
          <div className="relative">
            <FaSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder={`${t('search')} medicines...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input pl-10"
            />
          </div>

          {/* Category Filter */}
          <div className="relative">
            <FaFilter className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              className="input pl-10"
            >
              <option value="">All Categories</option>
              {categories.map(category => (
                <option key={category} value={category}>{category}</option>
              ))}
            </select>
          </div>

          {/* Stock Filter */}
          <select
            value={stockFilter}
            onChange={(e) => setStockFilter(e.target.value)}
            className="input"
          >
            <option value="all">All Stock Levels</option>
            <option value="low_stock">Low Stock</option>
            <option value="out_of_stock">Out of Stock</option>
          </select>

          {/* Quick Stats */}
          <div className="flex items-center justify-center bg-gray-50 rounded-lg p-3">
            <div className="text-center">
              <div className="text-2xl font-bold text-primary-color">{medicines.length}</div>
              <div className="text-sm text-gray-600">Total Medicines</div>
            </div>
          </div>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-100 border border-red-300 text-red-700 p-4 rounded-lg mb-6">
          {error}
        </div>
      )}

      {/* Stock Alerts */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <div className="bg-green-50 border border-green-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <FaCheckCircle className="text-2xl text-green-500" />
            <div>
              <div className="text-lg font-semibold text-green-800">
                {medicines.filter(m => m.stock_quantity >= 10).length}
              </div>
              <div className="text-sm text-green-600">In Stock</div>
            </div>
          </div>
        </div>
        
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <FaExclamationTriangle className="text-2xl text-yellow-500" />
            <div>
              <div className="text-lg font-semibold text-yellow-800">
                {medicines.filter(m => m.stock_quantity > 0 && m.stock_quantity < 10).length}
              </div>
              <div className="text-sm text-yellow-600">Low Stock</div>
            </div>
          </div>
        </div>
        
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <FaTimesCircle className="text-2xl text-red-500" />
            <div>
              <div className="text-lg font-semibold text-red-800">
                {medicines.filter(m => m.stock_quantity === 0).length}
              </div>
              <div className="text-sm text-red-600">Out of Stock</div>
            </div>
          </div>
        </div>
      </div>

      {/* Medicines Table */}
      <div className="bg-white rounded-lg shadow-sm border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="text-left p-4 font-medium text-gray-900">{t('medicine_name')}</th>
                <th className="text-left p-4 font-medium text-gray-900">Generic Name</th>
                <th className="text-left p-4 font-medium text-gray-900">Manufacturer</th>
                <th className="text-right p-4 font-medium text-gray-900">{t('price')}</th>
                <th className="text-center p-4 font-medium text-gray-900">{t('stock')}</th>
                <th className="text-center p-4 font-medium text-gray-900">Status</th>
                <th className="text-center p-4 font-medium text-gray-900">{t('expiry_date')}</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {filteredMedicines.map((medicine) => (
                <tr key={medicine.id} className="hover:bg-gray-50">
                  <td className="p-4">
                    <div className="flex items-start gap-3">
                      <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-lg flex items-center justify-center text-white">
                        <FaPills />
                      </div>
                      <div>
                        <div className="font-medium text-gray-900">{medicine.name}</div>
                        <div className="text-sm text-gray-600">{medicine.category}</div>
                        {medicine.requires_prescription && (
                          <span className="inline-block mt-1 px-2 py-1 bg-orange-100 text-orange-800 text-xs rounded-full">
                            Prescription Required
                          </span>
                        )}
                      </div>
                    </div>
                  </td>
                  
                  <td className="p-4">
                    <div className="text-gray-900">{medicine.generic_name}</div>
                    <div className="text-sm text-gray-600">{medicine.description}</div>
                  </td>
                  
                  <td className="p-4">
                    <div className="flex items-center gap-2">
                      <FaIndustry className="text-gray-400 text-sm" />
                      <span className="text-gray-900">{medicine.manufacturer}</span>
                    </div>
                  </td>
                  
                  <td className="p-4 text-right">
                    <div className="flex items-center justify-end gap-1">
                      <FaRupeeSign className="text-gray-400 text-sm" />
                      <span className="font-semibold text-gray-900">{medicine.price.toFixed(2)}</span>
                    </div>
                  </td>
                  
                  <td className="p-4 text-center">
                    <div className="text-lg font-semibold text-gray-900">
                      {medicine.stock_quantity}
                    </div>
                  </td>
                  
                  <td className="p-4 text-center">
                    <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium stock-indicator ${getStockStatus(medicine.stock_quantity)}`}>
                      {getStockStatusIcon(medicine.stock_quantity)}
                      {getStockStatusText(medicine.stock_quantity)}
                    </div>
                  </td>
                  
                  <td className="p-4 text-center">
                    <div className="flex items-center justify-center gap-2">
                      <FaCalendarAlt className="text-gray-400 text-sm" />
                      <span className={`text-sm ${isExpiringSoon(medicine.expiry_date) ? 'text-red-600 font-medium' : 'text-gray-600'}`}>
                        {formatDate(medicine.expiry_date)}
                      </span>
                    </div>
                    {isExpiringSoon(medicine.expiry_date) && (
                      <div className="text-xs text-red-600 mt-1">Expires Soon!</div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* No Results */}
      {filteredMedicines.length === 0 && !loading && (
        <div className="text-center py-12">
          <FaPills className="mx-auto text-6xl text-gray-300 mb-4" />
          <h3 className="text-xl font-medium text-gray-900 mb-2">No medicines found</h3>
          <p className="text-gray-600">
            Try adjusting your search criteria or filters
          </p>
        </div>
      )}

      {/* Results Summary */}
      {filteredMedicines.length > 0 && (
        <div className="mt-6 text-center text-gray-600">
          Showing {filteredMedicines.length} of {medicines.length} medicines
        </div>
      )}
    </div>
  );
};

export default Medicines;
